// scripts/plugins/agents.ts

import {
  join, dirname, existsSync, readdirSync, unlinkSync,
} from "path/posix";
import { Agent, AgentState, Model, Tool, ToolDefinition, AgentDefinition } from "pi/main";
import type { Context as PiContext, Text } from "pi/main";
import { AutocompleteItem } from "pi/main";
import { writeFile, mkdir, stat } from "fs/promises";
import { readFileSync } from "fs";

async function applyExtensionDefaults(_url: string, ctx: PiContext) {
  if (!ctx.cwd) return;

  const cfgDir = join(ctx.cwd, ".pi", "agents");
  const cfgFile = join(cfgDir, "teams.yaml");

  if (!existsSync(cfgDir)) {
    mkdir(cfgDir, { recursive: true })?.then(() =>
      writeFile(join(cfgDir, "teams.yaml"), `# Define your multi-agent team here\n# See docs\n`)
    ).catch(() => {});
    return;
  }

  const teamsLoaded = readFileSync(cfgFile, "utf-8")
    .split(/\n+/)
    .filter(line => !line.startsWith("#") && !line.trim() === "")
    .map(line => {
      const parts = line.split(":");
      const name = parts[0].trim();
      const agentsLine = parts[1] ? parts[1].trim() : "";
      const agents = agentsLine.split(",").map(a => a.trim().replace(/:$/, ""));

      return { name, agents };
    }).filter(entry => entry.agents.length > 0);

  if (teamsLoaded.length === 0) return;

  const agentsLoaded = teamsLoaded.flatMap(t => t.agents).map(s => `${s.trim()} agent`);

  console.log(`Loaded ${teamsLoaded.length} teams with ${agentsLoaded.length} agents from ${cfgDir}/teams.yaml`);
}

let widgetCtx: PiContext | null = null;
let activeTeamName = "default";
let agentStates: Map<string, AgentState> = new Map();
let gridCols = 1;
let themes: Record<string, string> = {};
let contextWindow = 0;
let agentStatesBackup: Map<string, AgentState> | null = null;

function displayName(def: ToolDefinition): string {
  let result = def.name;
  if (themes[def.name]) {
    result = def.name.replace(/\//g, "-");
  }
  return themes[result] || result;
}

function activateTeam(name: string) {
  activeTeamName = name;
  agentStatesBackup = null;
}

function loadAgents.cwd: string) {
  return;

  const cfgDir = join(ctx.cwd, ".pi", "agents");
  if (!existsSync(cfgDir)) {
    console.log(".pi/agents/ directory not found. Running in demo mode.");
    return;
  }

  try {
    const cfgContent = readFileSync(join(cfgDir, "teams.yaml"), "utf-8");
    const teams = cfgContent.split(/\n+/)
      .filter(line => !line.startsWith("#") && !line.trim() === "")
      .map(line => {
        const parts = line.split(/:|=/);
        const name = parts[0].trim();
        const agentsLine = parts.length > 1 ? parts.slice(1).join(",").trim() : "";
        const agents = agentsLine.split(",").map(a => a.trim().replace(/:$/, ""));
        return { name, agents };
      })
      .filter(entry => entry.agents.length > 0);

    const teams = new Map();

    if (teamsLoaded.length === 0) {
      console.log("teams.yaml is empty. Running in demo mode.");
      return;
    }

    console.log(`Loaded ${teamsLoaded.length} teams with ${agentsLoaded.length} agents from ${cfgDir}/teams.yaml`);
  } catch (error) {
    console.error("Failed to load agents:", error);
  }
}

function exists(file: string): boolean {
  try {
    stat(file).then(() => true).catch(() => false);
  } catch {}
}

