// Above editor (default)
ctx.ui.setWidget("my-widget", ["Line 1", "Line 2"]);

// Below editor
ctx.ui.setWidget("my-widget", ["Line 1", "Line 2"], { placement: "belowEditor" });

// With custom theme/styling
ctx.ui.setWidget("my-widget", (_tui, theme) => {
  return {
    render: () => lines,
    invalidate: () => {},
  };
});
```

### 4. Custom Footer
Replace or enhance the footer with `setFooter()`. Exposes `footerData` with app stats like git branch.

```typescript
ctx.ui.setFooter((tui, theme, footerData) => ({
  invalidate() {},
  render(width: number): string[] {
    return [`🔧 ${ctx.model?.id} (${footerData.getGitBranch() || "no git"})`];
  },
  dispose: footerData.onBranchChange(() => tui.requestRender()),
}));
```

### 5. Custom Editor
Override the input editor for vim mode, modal editing, custom keybindings.

```typescript
class VimEditor extends CustomEditor {
  handleInput(data: string): void {
    if (matchesKey(data, "escape")) {
      // Handle escape
      return;
    }
    super.handleInput(data);
  }
}

ctx.ui.setEditorComponent((tui, theme, keybindings) => 
  new VimEditor(theme, keybindings)
);
```

## Best Practices

### 1. ✅ Always Use Theme from Callback
Never import theme statically. Use the `theme` parameter from your component's factory function.

### 2. ✅ Type Dynamic Border Colors
Explicitly type color parameters to avoid issues:
```typescript
const dynamicBorder = (s: string) => theme.fg("accent", s);
```

### 3. ✅ Call `tui.requestRender()` After State Changes
Always trigger re-render when data changes in `handleInput`.

### 4. ✅ Return Required Object
Custom components must return `{ render, invalidate, handleInput }`.

### 5. ✅ Reuse Existing Components
`SelectList`, `SettingsList`, `BorderedLoader` cover 90% of use cases.

