│  └─────────────────────────────────────────────────────────┘ │
│                                                             │
│  ┌─────────────────────────────────────────────────────────┐ │
│  │              Session Status Registry                      │ │
│  │  Active | Idle | Saved | Cleared | Archived              │ │
│  └─────────────────────────────────────────────────────────┘ │
│                                                             │
│  ┌─────────────────────────────────────────────────────────┐ │
│  │              Analysis Engine                              │ │
│  │  Usage Metrics    │  Health Checks    │  Alerts          │ │
│  └─────────────────────────────────────────────────────────┘ │
└─────────────────────────────────────────────────────────────┘
```

---

## 📊 Components Breakdown

### 1. SessionMonitor Class

```typescript
// Location: extensions/session-manager.ts (internal class)

// Type definitions
type SessionStatus = 'active' | 'idle' | 'saved' | 'cleared' | 'archived'

interface SessionEvent {
  sessionId: string;
  timestamp: number;
  eventType: 'created' | 'message' | 'saved' | 'cleared' | 'idle' | 'archived';
  details?: any;
}

class SessionMonitor {
  // Instance variables
  private activeSessions: Map<string, SessionInfo>;
  private eventHistory: SessionEvent[];
  private lastActivity: Map<string, number>;
  private statusCallbacks: Map<string, (event: SessionEvent) => void>;

  // Responsibilities
  trackSessionCreation(sessionId: string)
  trackMessage(sessionId: string, prompt: string)
  trackSave(sessionId: string)
  trackClear(sessionId: string)
  updateIdleStatus(sessionId: string)
  emitEvent(event: SessionEvent)
  registerCallback(sessionId: string, callback: (event: SessionEvent) => void)
  unregisterCallback(sessionId: string)
  getActiveSessions(): SessionInformation[]
  getLastActivity(sessionId: string): number | null
}
```

### 2. StatusReporter Class

```typescript
class StatusReporter {
  // Reporting methods
  reportActivity(event: SessionEvent)
  statusOnRequest(): SessionStatusReport
  periodicStatus(interval?: number): void
  reportSessionList(): SessionListReport
  reportLastActivity(limit: number = 10): ActivityLog

  // Status report structure
  interface SessionStatusReport {
    timestamp: string;
    totalSessions: number;
    activeSessions: number;
    idleSessions: number;
    savedSessions: number;
    averageMessageCount: number;
    recentEvents: SessionEvent[]
  }

  // Activity log structure
  interface ActivityLog {
    sessionId: string;
    action: string;
    time: string;
    details: any;
  }
}
```

### 3. SessionAnalyzer Class

```typescript
class SessionAnalyzer {
  // Analysis methods
  analyzeUsageMetrics(): UsageReport
  generateHealthReport(): HealthReport
  detectAnomalies(): AnomalyReport
  calculateEngagement(): EngagementReport
  trendAnalysis(): TrendReport

  // Usage metrics
  interface UsageReport {
    mostActiveSession: SessionId;
    mostMessagesSession: SessionId;
    topConversationTopics: Topic[];
    peakActivityTime: string;
    totalTimeSpent: Map<string, string>;
  }

  // Health indicators
  interface HealthReport {
    overallHealth: 'healthy' | 'warning' | 'critical';
    inactiveSessions: string[];
    memoryUsage: number;
    retentionPolicy: string;
    cleanupRecommended: boolean;
  }

  // Alerts
  interface AnomalyReport {
    anomalyType: string;
    sessionId: string;
    severity: 'low' | 'medium' | 'high';
    message: string;
    suggestion: string;
  }
}
```

### 4. AlertManager Class

```typescript
class AlertManager {
  // Alert configuration
  alertThreshold: {
    idleTimeout: number; // seconds
    messageCountLimit: number;
    retentionDays: number;
    warningLevels: {
      idle: number; // seconds
      largeSession: number; // messages
      unusualActivity: boolean;
    }
  }

  // Alert methods
  checkAndAlert(sessionId: string): Alert[]
  sendWarningAlert(alert: Alert)
  sendInfoAlert(alert: Alert)
  clearAlerts(sessionId?: string)
  getAlertHistory(): AlertLog[]

  // Alert types
  interface Alert {
    type: 'idle' | 'save' | 'large' | 'cleared' | 'new';
    priority: 'high' | 'medium' | 'low';
    message: string;
    actionSuggested?: string;
  }

  interface AlertLog {
    id: string;
    timestamp: string;
    sessionId?: string;
    alert: Alert;
    acknowledged: boolean;
  }
}
```

### 5. Command Handler

```typescript
class SessionCommandHandler {
  // Commands
  register(command: CommandDefinition)
  handleCommand(input: string, sessionId?: string): string

  // Command definitions
  interface CommandDefinition {
    trigger: string;
    description: string;
    handler: (input: string) => string
  }

  // Command list
  /status      - Show current session status
  /sessions    - List all saved sessions
  /last N      - Show last N session events
  /monitor     - Enable/demonitor alerts
  /alerts      - Show alert history
  /clear       - Clear current session (with confirmation)
